#include <iostream>
#include <iomanip>
#include <cmath>
#include <vector>

using namespace std;

// Function to generate a complex pattern with numbers and letters
void generateComplexPattern(int rows) {
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < rows; ++j) {
            // Calculate the number based on the row and column indices
            int num = i * rows + j;
            // Determine the character to print
            char ch = 'A' + (num % 26);
            cout << ch;
        }
        cout << endl;
    }
}

// Function to highlight a specific section of the pattern
void highlightSection(int startRow, int endRow, int startCol, int endCol) {
    for (int i = startRow; i <= endRow; ++i) {
        for (int j = startCol; j <= endCol; ++j) {
            // Check if the current position contains the letter 'j'
            if (j == 10) {
                cout << "*";
            } else {
                cout << " ";
            }
        }
        cout << endl;
    }
}

// Main function to run the program
int main() {
    int rows = 5;
    cout << "Complex Pattern with Numbers and Letters:\n";

    // Generate the main pattern
    generateComplexPattern(rows);

    // Highlight a specific section
    highlightSection(1, 3, 1, 5);

    // Output the highlighted section
    cout << "\nHighlighted Section:\n";
    highlightSection(1, 3, 1, 5);

    cout << "\nIs there anything else I can help with?";
    return 0;
}
